INSERT INTO STOCVOCD (
      GATE_CD
    , VC_NO
    , COMPANY_CD
    , VC_SQ
    , REG_DATE
    , REG_USER_ID
    , BUYER_CD
    , DEPT_CD
)
VALUES (
      #{ses.gateCd}
    , #{VC_NO}
    , #{ses.companyCd}
    ,(SELECT (MAX(VC_SQ) + 1, 1) FROM STOCVOCD WHERE GATE_CD = #{ses.gateCd} AND VC_NO = #{VC_NO})
    , SYSDATE
    , #{ses.userId}
    , #{BUYER_CD}
    , #{DEPT_CD}
)

