      MOD_DATE    = SYSDATE
    , MOD_USER_ID = #{ses.userId}
    , PROGRESS_CD = #{PROGRESS_CD}
    , SUBJECT     = #{SUBJECT}
    , REQ_DATE    = (#{REQ_DATE}, 'YYYY-MM-DD HH24:MI:SS')
    , VOC_TYPE    = #{VOC_TYPE}
    , PH_DATE     = (#{PH_DATE}, SYSDATE)
    , ORDER_NO    = #{ORDER_NO}
    , ITEM_CD     = #{ITEM_CD}
    , REQ_RMK     = #{REQ_RMK}
    , ATTACH_FILE_NO = #{ATTACH_FILE_NO}
WHERE GATE_CD = #{ses.gateCd}
  AND VC_NO   = #{VC_NO}

UPDATE STOCVOCD SET
      MOD_DATE    = SYSDATE
    , MOD_USER_ID = #{ses.userId}
    , PROGRESS_CD = #{PROGRESS_CD}


    , RECV_DATE   = SYSDATE
    , RECV_USER_ID= #{ses.userId}
    , CONF_RMKS   = #{DF_RMK}
    , ATTACH_FILE_NO = #{DS_ATTACH_FILE_NO}



    , RECV_DATE   = (RECV_DATE, SYSDATE)
    , RECV_USER_ID= (RECV_USER_ID, #{ses.userId})
    , CONF_DATE   = SYSDATE
    , CONF_USER_ID= #{ses.userId}
    , CONF_RMKS   = #{DF_RMK}
    , ATTACH_FILE_NO = #{DS_ATTACH_FILE_NO}

WHERE GATE_CD = #{ses.gateCd}
  AND VC_NO   = #{VC_NO}
  AND VC_SQ   = #{VC_SQ}

